\begin{lemma}\label{lem: units stabilize}
Let $\calA$ be a unital associative algebra. For every $u_0 \vvirg u_k \in U(\calA)$, we have
\[
(u_0 \vvirg u_k) \cdot T_\calA^{(k)} = T_\calA^{(k)}.
\]
\end{lemma}

