\begin{proposition}\label{prop: R qnd Q as k grows}
Let $\calA$ be an associative unital algebra. Then, for every $k$,
\begin{itemize}
\item $\uR(T^{(k)}_{\calA}) \leq  \uR(T^{(k+1)}_{\calA})$,
\item $\uQ(T^{(k)}_{\calA}) \geq  \uQ(T^{(k+1)}_{\calA})$.
\end{itemize}
\end{proposition}

