\begin{theorem}\label{thm: main MaMu}
Let $k \geq 3$, $n \geq 2$ be integers. Let $q = \lfloor n/k\rfloor$ and $r = n - qk$. Then
\[
\frac{n^2}{k-1}\leq \uQ(\MaMu_{(n \vvirg n)}) \leq  \frac{1}{2} ( n^2 + nq + r(q+1))
\]
\end{theorem}

