\begin{theorem}\label{thm: sl lie algebra}
    Let $n\geq 2$ and $k\geq 2$. Then 
    \begin{itemize}
    \item if $k = 2$ then 
    \[
    n \leq \rmQ(T^{(2)}_{\mathfrak{sl}_n}) \leq \uQ(T^{(2)}_{\mathfrak{sl}_n}) \leq n^2-n;
    \]
    \item if $n = 2$ then $\uQ(T^{(k)}_{\mathfrak{sl}_2}) = 2$ for every $k$. 
    \end{itemize}
\end{theorem}

